import{_ as t,o,c as i,ag as r}from"./chunks/framework.C9sp7nFj.js";const d=JSON.parse('{"title":"Biometric unlock","description":"","frontmatter":{},"headers":[],"relativePath":"guide/biometric.md","filePath":"guide/biometric.md","lastUpdated":1776621628000}'),a={name:"guide/biometric.md"};function n(s,e,l,p,h,c){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="biometric-unlock" tabindex="-1">Biometric unlock <a class="header-anchor" href="#biometric-unlock" aria-label="Permalink to &quot;Biometric unlock&quot;">​</a></h1><p>Skip the PIN pad — unlock Fateh HR with your fingerprint, face, or iris.</p><h2 id="what-you-ll-see" tabindex="-1">What you&#39;ll see <a class="header-anchor" href="#what-you-ll-see" aria-label="Permalink to &quot;What you&#39;ll see&quot;">​</a></h2><p>On any Android phone that has biometric hardware you&#39;ve set up at the OS level (fingerprint enrolled in Settings, or Face Unlock configured), Fateh HR can use it.</p><p>The label in the app adapts to your device:</p><ul><li><strong>Fingerprint</strong> — capacitive / in-display fingerprint readers</li><li><strong>Face Unlock</strong> — face-based unlock (Google&#39;s or manufacturer&#39;s)</li><li><strong>Iris Unlock</strong> — some Samsung devices</li><li><strong>Touch ID / Face ID</strong> — iOS (web version; see note below)</li></ul><h2 id="enabling-it" tabindex="-1">Enabling it <a class="header-anchor" href="#enabling-it" aria-label="Permalink to &quot;Enabling it&quot;">​</a></h2><p>There are two places you can enable it.</p><h3 id="option-1-—-from-the-more-tab-any-time" tabindex="-1">Option 1 — From the More tab (any time) <a class="header-anchor" href="#option-1-—-from-the-more-tab-any-time" aria-label="Permalink to &quot;Option 1 — From the More tab (any time)&quot;">​</a></h3><ol><li>Open the <strong>More</strong> tab (bottom-right of the screen).</li><li>Scroll to the <strong>Security</strong> card.</li><li>Tap the toggle next to <strong>&quot;Unlock with Fingerprint&quot;</strong> (or Face ID / whatever your device shows).</li><li>Your phone&#39;s native biometric prompt appears — place your finger / look at the screen.</li><li>Toggle flips green. Done.</li></ol><p>This is the recommended path if you&#39;ve been using the app for a while and haven&#39;t seen the enrollment prompt.</p><h3 id="option-2-—-after-setting-a-pin-new-or-reset" tabindex="-1">Option 2 — After setting a PIN (new or reset) <a class="header-anchor" href="#option-2-—-after-setting-a-pin-new-or-reset" aria-label="Permalink to &quot;Option 2 — After setting a PIN (new or reset)&quot;">​</a></h3><p>You&#39;ll be asked automatically once, right after a successful <strong>PIN setup</strong> (either your first PIN or a reset via Forgot PIN). A small card slides up:</p><blockquote><p><strong>Enable Fingerprint?</strong></p><p><em>Unlock the app with Fingerprint instead of typing your PIN. Your PIN will remain as a backup.</em></p><p><strong>[Not now] [Enable Fingerprint]</strong></p></blockquote><p>Tap <strong>Enable</strong> → phone&#39;s biometric prompt → done.</p><p>If you tap <strong>Not now</strong>, you can still enable it later from the More tab (see Option 1).</p><div class="tip custom-block"><p class="custom-block-title">Why didn&#39;t I see the prompt?</p><p>The one-time enrollment modal only appears immediately after saving a <strong>new</strong> PIN. If you upgraded the app while keeping your existing PIN, the modal won&#39;t fire — use <strong>Option 1</strong> from the More tab instead.</p></div><h2 id="turning-it-off" tabindex="-1">Turning it off <a class="header-anchor" href="#turning-it-off" aria-label="Permalink to &quot;Turning it off&quot;">​</a></h2><p>Same <strong>Security</strong> card → tap the green toggle again. It flips off. Next time you open the app, you&#39;ll type your PIN as normal.</p><h2 id="daily-use" tabindex="-1">Daily use <a class="header-anchor" href="#daily-use" aria-label="Permalink to &quot;Daily use&quot;">​</a></h2><p>From now on, opening Fateh HR does this:</p><ol><li>PIN screen appears</li><li>Biometric prompt <strong>pops up automatically</strong> on the same screen</li><li>Touch the sensor / face scan → you&#39;re at the home screen</li></ol><p>No typing needed.</p><h2 id="if-biometric-fails" tabindex="-1">If biometric fails <a class="header-anchor" href="#if-biometric-fails" aria-label="Permalink to &quot;If biometric fails&quot;">​</a></h2><p>The biometric prompt is the OS&#39;s — not ours. It handles failure natively (three failed attempts on most Androids, then it backs off). When it fails or you cancel:</p><ul><li>The prompt disappears</li><li>You stay on the PIN screen</li><li><strong>Type your PIN</strong> to unlock as before</li><li>A <strong>&quot;Use Fingerprint&quot;</strong> button stays at the bottom to retry biometric</li></ul><p><strong>Your PIN always works</strong> as a fallback. Biometric is just faster when it&#39;s working.</p><h2 id="security-notes" tabindex="-1">Security notes <a class="header-anchor" href="#security-notes" aria-label="Permalink to &quot;Security notes&quot;">​</a></h2><ul><li>We <strong>never store your fingerprint or face image</strong> — that lives only in your phone&#39;s secure enclave.</li><li>The biometric prompt acts as <strong>proof of identity</strong> — when it passes, the app trusts that you are you and unlocks. The PIN check is skipped.</li><li>Uninstalling the app clears the enrolment flag. You&#39;ll re-enrol when you reinstall.</li><li>If you switch phones, biometric enrolment doesn&#39;t transfer — the new phone prompts you after your first PIN setup.</li></ul><h2 id="on-iphone-web-version" tabindex="-1">On iPhone / web version <a class="header-anchor" href="#on-iphone-web-version" aria-label="Permalink to &quot;On iPhone / web version&quot;">​</a></h2><p>The web version (Safari or Chrome on iPhone) doesn&#39;t currently support biometric unlock — iOS locks biometric APIs to native apps. Use your PIN.</p><p>A native iOS app is on our roadmap.</p><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/guide/check-in">Your first check-in</a></li><li><a href="/guide/offline">How offline mode works</a></li></ul>',34)])])}const m=t(a,[["render",n]]);export{d as __pageData,m as default};
